import{_ as t,o as a,c as o,a0 as d}from"./chunks/framework.BjpW4enL.js";const u=JSON.parse('{"title":"ADR-0022: Auditoria de Implementação — Estado Atual vs ADRs","description":"","frontmatter":{},"headers":[],"relativePath":"20_Arquitetura/adr/0022-nexus-implementation-audit.md","filePath":"20_Arquitetura/adr/0022-nexus-implementation-audit.md","lastUpdated":1782592277000}'),r={name:"20_Arquitetura/adr/0022-nexus-implementation-audit.md"};function i(s,e,n,c,l,p){return a(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="adr-0022-auditoria-de-implementacao-—-estado-atual-vs-adrs" tabindex="-1">ADR-0022: Auditoria de Implementação — Estado Atual vs ADRs <a class="header-anchor" href="#adr-0022-auditoria-de-implementacao-—-estado-atual-vs-adrs" aria-label="Permalink to &quot;ADR-0022: Auditoria de Implementação — Estado Atual vs ADRs&quot;">​</a></h1><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Aceito (2026-06-16)</p><h2 id="contexto" tabindex="-1">Contexto <a class="header-anchor" href="#contexto" aria-label="Permalink to &quot;Contexto&quot;">​</a></h2><p>O NEXUS acumulou 21 ADRs (3 ativos, 18 arquivados) durante seu desenvolvimento. Este ADR documenta uma auditoria sistemática comparando o <strong>estado atual implementado</strong> com o <strong>estado especificado</strong> em cada ADR, identificando gaps, decisões já executadas e riscos não endereçados.</p><p>A auditoria foi realizada em 2026-06-16 sobre o código em produção (Docker Compose) e o código fonte do Rust coordinator em <code>services/coordinator/src/</code>.</p><h2 id="metodologia" tabindex="-1">Metodologia <a class="header-anchor" href="#metodologia" aria-label="Permalink to &quot;Metodologia&quot;">​</a></h2><p>Para cada ADR, foi verificado:</p><ol><li><strong>Schema no PostgreSQL</strong> — colunas, constraints, índices</li><li><strong>Código Rust</strong> — implementação no coordinator (enrich, weaver, deps, t4, query, l3)</li><li><strong>Código Python</strong> — MCP server tools</li><li><strong>Estado no banco</strong> — dados reais (counts, valores)</li><li><strong>Comportamento via HTTP</strong> — endpoints respondendo corretamente</li></ol><h2 id="resultados-consolidados" tabindex="-1">Resultados Consolidados <a class="header-anchor" href="#resultados-consolidados" aria-label="Permalink to &quot;Resultados Consolidados&quot;">​</a></h2><h3 id="adrs-ativos-current" tabindex="-1">ADRs Ativos (Current) <a class="header-anchor" href="#adrs-ativos-current" aria-label="Permalink to &quot;ADRs Ativos (Current)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ADR</th><th>Título</th><th>Status no ADR</th><th>Implementação</th></tr></thead><tbody><tr><td>0001</td><td>Propagação de Carga e Retropropagação</td><td>Proposto</td><td>❌ Não iniciado</td></tr><tr><td>0002</td><td>Operadores Relacionais Composáveis T4</td><td>Proposto</td><td>⚠️ Parcial (find, expand, project OK)</td></tr></tbody></table><h3 id="adrs-arquivados-legacy" tabindex="-1">ADRs Arquivados (Legacy) <a class="header-anchor" href="#adrs-arquivados-legacy" aria-label="Permalink to &quot;ADRs Arquivados (Legacy)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ADR</th><th>Título</th><th>Relevância</th><th>Implementação</th></tr></thead><tbody><tr><td>0006</td><td>Horizonte Topológico</td><td>📦</td><td>Não auditado (pré-Rust)</td></tr><tr><td>0007</td><td>Causalidade Topológica</td><td>📦</td><td>Não auditado (pré-Rust)</td></tr><tr><td>0009</td><td>Synesthetic Topology</td><td>📦</td><td>Não auditado (pré-Rust)</td></tr><tr><td>0010</td><td>Abstraction Levels &amp; Time</td><td>🟡 Relevante</td><td>⚠️ Parcial</td></tr><tr><td>0011</td><td>T5 Algebraic Space Speculation</td><td>📦</td><td>Não implementado</td></tr><tr><td>0014</td><td>Semantic Drift Gatekeeper</td><td>🟡 Relevante</td><td>✅ Implementado</td></tr><tr><td>0015</td><td>Agent Stigmergy Triangulation</td><td>🟡 Relevante</td><td>⚠️ Parcial</td></tr><tr><td>0016</td><td>CLI-Independent Universal MCP</td><td>🟡 Relevante</td><td>✅ Implementado</td></tr><tr><td>0017</td><td>L2 Structure Inheritance from L1</td><td>🟡 Relevante</td><td>✅ Implementado</td></tr><tr><td>0018</td><td>Hallucination Detection</td><td>🟡 Relevante</td><td>✅ Implementado</td></tr><tr><td>0020</td><td>Trajectory Subgraph Retrieval</td><td>🟡 Relevante</td><td>❌ Não iniciado</td></tr><tr><td>0021</td><td>Forgetful Swarm Dynamics</td><td>🟡 Relevante</td><td>❌ Não iniciado</td></tr></tbody></table><h2 id="detalhamento-por-adr" tabindex="-1">Detalhamento por ADR <a class="header-anchor" href="#detalhamento-por-adr" aria-label="Permalink to &quot;Detalhamento por ADR&quot;">​</a></h2><h3 id="adr-0001-propagacao-de-carga-e-retropropagacao-dinamica" tabindex="-1">ADR-0001: Propagação de Carga e Retropropagação Dinâmica <a class="header-anchor" href="#adr-0001-propagacao-de-carga-e-retropropagacao-dinamica" aria-label="Permalink to &quot;ADR-0001: Propagação de Carga e Retropropagação Dinâmica&quot;">​</a></h3><p><strong>O que especifica:</strong></p><ul><li>Algoritmo de Graph Signal Processing (GSP) com polinômios de Chebyshev</li><li>Cargas dipolo e campos de potencial entre nós (<code>±q</code> com decaimento cosseno)</li><li>Retropropagação de feedback (stigmergy dinâmica) com equação de atualização de pesos</li><li>Operadores de translado (<code>T_v</code>) e dilatação (<code>D_s</code>) via wavelets espectrais</li><li>Complexidade alvo O(N log N) via Chebyshev truncado</li></ul><p><strong>O que existe:</strong></p><ul><li><code>base_weight</code> na tabela <code>agent_links</code> (estático, nunca atualizado)</li><li>115.521 arestas no grafo T4 com pesos fixos</li></ul><p><strong>Gap:</strong> Nenhum componente de GSP, Chebyshev, wavelets ou retropropagação foi implementado. O grafo T4 é estático — pesos não evoluem com navegação de agentes.</p><hr><h3 id="adr-0002-operadores-relacionais-composaveis-t4-opcao-3" tabindex="-1">ADR-0002: Operadores Relacionais Composáveis T4 (Opção 3) <a class="header-anchor" href="#adr-0002-operadores-relacionais-composaveis-t4-opcao-3" aria-label="Permalink to &quot;ADR-0002: Operadores Relacionais Composáveis T4 (Opção 3)&quot;">​</a></h3><p><strong>O que especifica:</strong></p><ul><li><code>find(subgraph_schema)</code> — encontrar subgrafos por schema de entidade</li><li><code>expand(entity, criteria_set)</code> — expandir fronteira por tipo de aresta</li><li><code>project(entity, axes)</code> — fatiar subgrafo por eixos (criteria × file_type × project)</li><li><code>abstract(entities)</code> — generalizar múltiplas entidades em forma canônica</li><li><code>compile(form, engine)</code> — materializar forma canônica em schema concreto</li><li><code>chain(entity, operator)</code> — compor operadores serializáveis como &quot;leis&quot;</li></ul><p><strong>O que existe:</strong></p><ul><li>✅ <code>project</code> — endpoint <code>/t4/project</code> com filtros criteria/file_type/project/module</li><li>✅ <code>expand</code> — MCP tool <code>nexus_adjacent</code> caminha grafo T4</li><li>✅ <code>find</code> — MCP tool <code>nexus_query</code> (T3) + <code>nexus_map</code> (topografia)</li></ul><p><strong>Gap:</strong> <code>abstract</code>, <code>compile</code> e <code>chain</code> não implementados. Sem runtime de pipelines topológicos. Sem Weisfeiler-Lehman. Sem Entity como subgrafo.</p><hr><h3 id="adr-0010-abstraction-levels-time" tabindex="-1">ADR-0010: Abstraction Levels &amp; Time <a class="header-anchor" href="#adr-0010-abstraction-levels-time" aria-label="Permalink to &quot;ADR-0010: Abstraction Levels &amp; Time&quot;">​</a></h3><p><strong>O que especifica:</strong></p><table tabindex="0"><thead><tr><th>Item</th><th>Descrição</th><th>Estado</th></tr></thead><tbody><tr><td>L0</td><td>Raw chunks (~2000 chars)</td><td>✅ Implementado</td></tr><tr><td>L1</td><td>AST determinístico (ast-grep)</td><td>✅ Implementado</td></tr><tr><td>L2</td><td>Semântico via LLM (qwen2.5-coder)</td><td>✅ Implementado</td></tr><tr><td>L3</td><td>Síntese arquitetural por blob</td><td>❌ <strong>Vazio (0 rows)</strong></td></tr><tr><td>L4</td><td>Síntese cross-blob (experimental)</td><td>⚠️ File nodes (2.327) OK, emergent não</td></tr><tr><td>L4 file node</td><td>Nó representando arquivo completo</td><td>✅ 2.327 nós L4</td></tr><tr><td>L5</td><td>Hipóteses falsificáveis</td><td>❌ Não implementado</td></tr><tr><td>L6</td><td>Modelo mental do projeto</td><td>❌ Não implementado</td></tr><tr><td>Decay</td><td><code>last_accessed_at</code> como peso em queries</td><td>❌ Coluna existe, nunca atualizada</td></tr><tr><td>Evolução</td><td><code>prev_blob_id</code> + <code>is_current</code> + successor</td><td>✅ Implementado via weaver</td></tr><tr><td>Fronteira Fractal</td><td>L3 contextualizado por vizinhos topológicos</td><td>❌ Não implementado</td></tr><tr><td>Pipeline 2 estágios L3</td><td>Mistral provocador → modelo externo</td><td>❌ Não implementado</td></tr><tr><td>Rotação de sementes</td><td>Papel × Foco × Tom no L3</td><td>❌ Não implementado</td></tr></tbody></table><hr><h3 id="adr-0014-semantic-drift-gatekeeper-✅" tabindex="-1">ADR-0014: Semantic Drift Gatekeeper ✅ <a class="header-anchor" href="#adr-0014-semantic-drift-gatekeeper-✅" aria-label="Permalink to &quot;ADR-0014: Semantic Drift Gatekeeper ✅&quot;">​</a></h3><p><strong>Implementado:</strong></p><ul><li>Cálculo de drift cross-representation: <code>1 - cosine(L2_neighbor, L0_current)</code></li><li>Threshold τ = 0.35 no <code>enrich.rs</code> (linha 676)</li><li>Fallback: vizinho sem L2 é aceito</li><li>Logging: <code>rejected neighbor &lt;path&gt; from Fractal Boundary</code></li></ul><p><strong>Evidência:</strong> Código em <code>enrich.rs</code> linhas 675-679.</p><hr><h3 id="adr-0015-agent-stigmergy-triangulation-⚠️-parcial" tabindex="-1">ADR-0015: Agent Stigmergy Triangulation ⚠️ Parcial <a class="header-anchor" href="#adr-0015-agent-stigmergy-triangulation-⚠️-parcial" aria-label="Permalink to &quot;ADR-0015: Agent Stigmergy Triangulation ⚠️ Parcial&quot;">​</a></h3><p><strong>Implementado:</strong></p><ul><li>Schema <code>agent_links</code> com colunas <code>ast_validated</code>, <code>target_hash_at_creation</code> ✅</li><li>Trigger de <code>content_hash</code> nas abstrações ✅</li><li>Índices UNIQUE <code>(source_id, target_id, criteria)</code> ✅</li></ul><p><strong>Não implementado:</strong></p><ul><li><code>ast_validated</code> nunca populado — <strong>zero</strong> linhas com <code>ast_validated = TRUE</code></li><li>MCP tool <code>nexus_link</code> <strong>não encontrada</strong> no MCP server atual</li><li>MCP tool <code>nexus_validate_link</code> <strong>não encontrada</strong></li><li>Bônus 1.5× de energia para links validados nunca aplicado</li></ul><hr><h3 id="adr-0016-cli-independent-universal-mcp-✅" tabindex="-1">ADR-0016: CLI-Independent Universal MCP ✅ <a class="header-anchor" href="#adr-0016-cli-independent-universal-mcp-✅" aria-label="Permalink to &quot;ADR-0016: CLI-Independent Universal MCP ✅&quot;">​</a></h3><p><strong>Implementado:</strong></p><ul><li>MCP server containerizado, exposto via SSE em <code>http://localhost:7474/sse</code></li><li>Stack completa em Docker Compose (<code>docker compose up</code>)</li><li>Qualquer CLI compatível com MCP pode se conectar</li></ul><hr><h3 id="adr-0017-l2-structure-inheritance-from-l1-✅" tabindex="-1">ADR-0017: L2 Structure Inheritance from L1 ✅ <a class="header-anchor" href="#adr-0017-l2-structure-inheritance-from-l1-✅" aria-label="Permalink to &quot;ADR-0017: L2 Structure Inheritance from L1 ✅&quot;">​</a></h3><p><strong>Implementado:</strong></p><ul><li>Merge L1→L2 no enrich.rs Phase 2 (linhas 952-964)</li><li><code>merged = l1_json.clone()</code> + <code>merged_obj.insert(&quot;purpose&quot;, purpose)</code></li><li>Fallback para blobs sem L1 (Markdown, etc.)</li></ul><p><strong>Evidência:</strong> Qdrant <code>nexus_ghost</code> contém L2 com estruturas L1 herdadas.</p><hr><h3 id="adr-0018-hallucination-detection-✅" tabindex="-1">ADR-0018: Hallucination Detection ✅ <a class="header-anchor" href="#adr-0018-hallucination-detection-✅" aria-label="Permalink to &quot;ADR-0018: Hallucination Detection ✅&quot;">​</a></h3><p><strong>Implementado:</strong></p><ul><li><code>hallucination_metrics</code> com <code>drift_score</code> no JSON</li><li>Regex com word boundaries: <code>\\b{}\\b</code></li><li>Cross-validation L1 constructs × L2 mentions</li></ul><p><strong>Evidência:</strong> Respostas do <code>/query</code> incluem <code>hallucination_metrics</code> com <code>drift_score</code>.</p><hr><h3 id="adr-0020-trajectory-subgraph-retrieval-❌" tabindex="-1">ADR-0020: Trajectory Subgraph Retrieval ❌ <a class="header-anchor" href="#adr-0020-trajectory-subgraph-retrieval-❌" aria-label="Permalink to &quot;ADR-0020: Trajectory Subgraph Retrieval ❌&quot;">​</a></h3><p><strong>Especifica:</strong></p><ul><li>Parâmetros <code>subgraph_depth</code>, <code>min_energy</code>, <code>allowed_relations</code> no <code>nexus_query</code></li><li>BFS walk no grafo T4 após seeds semânticos</li><li>CTE recursiva <code>graph_walk</code> com <code>v_active_stigmergic_graph</code></li><li>Context pack expandido com vizinhos do subgrafo</li></ul><p><strong>Estado:</strong> Nenhum dos parâmetros existe no <code>query.rs</code>. Sem implementação.</p><hr><h3 id="adr-0021-forgetful-swarm-dynamics-❌" tabindex="-1">ADR-0021: Forgetful Swarm Dynamics ❌ <a class="header-anchor" href="#adr-0021-forgetful-swarm-dynamics-❌" aria-label="Permalink to &quot;ADR-0021: Forgetful Swarm Dynamics ❌&quot;">​</a></h3><p><strong>Especifica:</strong></p><ul><li><code>decay_score</code> na tabela de links</li><li>Isolation Islands para tríades com drift &gt; 0.6 por 3 ciclos</li><li>Stigmergic Decay linear até threshold de desaparecimento</li><li>Worker DecayRoutine para períodos de baixa carga</li></ul><p><strong>Estado:</strong> Nada implementado. Schema sem <code>decay_score</code>.</p><h2 id="estado-do-sistema-base" tabindex="-1">Estado do Sistema (Base) <a class="header-anchor" href="#estado-do-sistema-base" aria-label="Permalink to &quot;Estado do Sistema (Base)&quot;">​</a></h2><p>Contagens atuais na produção (2026-06-16):</p><table tabindex="0"><thead><tr><th>Tabela</th><th>Count</th><th>Observação</th></tr></thead><tbody><tr><td>abstractions</td><td>69.985</td><td>L0+L1+L2+L4</td></tr><tr><td>agent_links</td><td>115.521</td><td>5 critérios</td></tr><tr><td>│— part_of</td><td>65.197</td><td>Hierarquia</td></tr><tr><td>│— semantic_bridge</td><td>37.071</td><td>Similaridade &gt; 0.90</td></tr><tr><td>│— successor</td><td>12.401</td><td>Continuidade cronológica</td></tr><tr><td>│— depends_on:imports</td><td>789</td><td>AST imports</td></tr><tr><td>│— contradicts</td><td>63</td><td>Drift semântico</td></tr><tr><td>blobs</td><td>2.366</td><td>Chunks de código</td></tr><tr><td>reflections</td><td>13.322</td><td>L2 summaries</td></tr><tr><td>module_synthesis</td><td>0</td><td>L3 vazio</td></tr><tr><td>fs_nodes</td><td>2.327</td><td>Arquivos monitorados</td></tr><tr><td>ingest_queue (pending)</td><td>1.034</td><td>Arquivos com falha</td></tr></tbody></table><h2 id="riscos-identificados" tabindex="-1">Riscos Identificados <a class="header-anchor" href="#riscos-identificados" aria-label="Permalink to &quot;Riscos Identificados&quot;">​</a></h2><ol><li><p><strong>L3 vazio</strong>: A síntese arquitetural (L3) nunca roda. O pipeline inteiro de abstração para no L2. Perde-se o valor mais alto do NEXUS — entender o que o sistema significa.</p></li><li><p><strong>Grafo T4 estático</strong>: 115k arestas sem dinâmica de aprendizado. Navegação de agentes não retroalimenta o sistema.</p></li><li><p><strong>ast_validated morto</strong>: Schema preparado mas funcionalidade nunca ativada. Indicação de que o ADR-0015 foi implementado parcialmente e nunca finalizado.</p></li><li><p><strong>Query sem expand</strong>: <code>nexus_query</code> retorna chunks planos sem subgraph expansion. Cada chamada precisa de múltiplas queries para obter contexto completo.</p></li><li><p><strong>Decay não usado</strong>: <code>last_accessed_at</code> coletado mas ignorado. Memória do sistema nunca desvanece — insights obsoletos têm o mesmo peso que atuais.</p></li></ol><h2 id="proximos-passos-recomendados" tabindex="-1">Próximos Passos Recomendados <a class="header-anchor" href="#proximos-passos-recomendados" aria-label="Permalink to &quot;Próximos Passos Recomendados&quot;">​</a></h2><p>Prioridade baseada em impacto vs esforço estimado:</p><ol><li><strong>Alta — L3 Synthesis</strong> (ADR-0010): Rodar L3 por blob, destravar o nível mais valioso</li><li><strong>Alta — Stigmergy Validation</strong> (ADR-0015): Popular <code>ast_validated</code>, expor MCP tools</li><li><strong>Média — Trajectory Subgraph</strong> (ADR-0020): Expandir query com BFS walk</li><li><strong>Média — Decay Temporal</strong> (ADR-0010): Ativar <code>last_accessed_at</code> nas queries</li><li><strong>Baixa — Topological Operators</strong> (ADR-0002): abstract, compile, chain</li><li><strong>Baixa — Forgetful Swarm</strong> (ADR-0021): decay_score + worker</li><li><strong>Futuro — Backpropagation</strong> (ADR-0001): GSP, Chebyshev, wavelets</li></ol><h2 id="referencias" tabindex="-1">Referências <a class="header-anchor" href="#referencias" aria-label="Permalink to &quot;Referências&quot;">​</a></h2><ul><li>ADR-0001: Propagação de Carga e Retropropagação (<code>docs/adr/0001-backpropagation-abstractions-charges.md</code>)</li><li>ADR-0002: Operadores Relacionais T4 (<code>docs/adr/0002-operadores-relacionais-componiveis-T4.md</code>)</li><li>ADR-0010: Abstraction Levels (<code>docs_archive_backup/.../0010-abstraction-levels-and-time.md</code>)</li><li>ADR-0014: Semantic Drift Gatekeeper (<code>docs_archive_backup/.../0014-semantic-drift-gatekeeper.md</code>)</li><li>ADR-0015: Agent Stigmergy Triangulation (<code>docs_archive_backup/.../0015-agent-stigmergy-triangulation.md</code>)</li><li>ADR-0016: Universal MCP (<code>docs_archive_backup/.../0016-cli-independent-universal-mcp.md</code>)</li><li>ADR-0017: L2 Structure Inheritance (<code>docs_archive_backup/.../0017-l2-structure-inheritance-from-l1.md</code>)</li><li>ADR-0018: Hallucination Detection (<code>docs_archive_backup/.../0018-hallucination-detection-and-mcp-refinement.md</code>)</li><li>ADR-0020: Trajectory Subgraph (<code>docs_archive_backup/.../0020-trajectory-subgraph-retrieval.md</code>)</li><li>ADR-0021: Forgetful Swarm (<code>docs/adr/0021-forgetful-swarm-dynamics.md</code>)</li></ul>',77)])])}const h=t(r,[["render",i]]);export{u as __pageData,h as default};
